// Internal utilities copied from mdast-util-to-markdown v2.x
// These are not exported by the package but are needed for custom handlers
function encodeCharacterReference(code) {
    return '&#x' + code.toString(16).toUpperCase() + ';';
}
export function containerPhrasing(parent, state, info) {
    const indexStack = state.indexStack;
    const children = parent.children || [];
    const results = [];
    let index = -1;
    let before = info.before;
    let encodeAfter;
    indexStack.push(-1);
    let tracker = state.createTracker(info);
    while (++index < children.length) {
        const child = children[index];
        let after;
        indexStack[indexStack.length - 1] = index;
        if (index + 1 < children.length) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            let handle = state.handle.handlers[children[index + 1].type];
            if (handle && handle.peek)
                handle = handle.peek;
            after = handle
                ? handle(children[index + 1], parent, state, {
                    before: '',
                    after: '',
                    ...tracker.current()
                }).charAt(0)
                : '';
        }
        else {
            after = info.after;
        }
        if (results.length > 0 &&
            (before === '\r' || before === '\n') &&
            child.type === 'html') {
            results[results.length - 1] = results[results.length - 1].replace(/(\r?\n|\r)$/, ' ');
            before = ' ';
            tracker = state.createTracker(info);
            tracker.move(results.join(''));
        }
        let value = state.handle(child, parent, state, {
            ...tracker.current(),
            after,
            before
        });
        if (encodeAfter && encodeAfter === value.slice(0, 1)) {
            value =
                encodeCharacterReference(encodeAfter.charCodeAt(0)) + value.slice(1);
        }
        const encodingInfo = state.attentionEncodeSurroundingInfo;
        state.attentionEncodeSurroundingInfo = undefined;
        encodeAfter = undefined;
        if (encodingInfo) {
            if (results.length > 0 &&
                encodingInfo.before &&
                before === results[results.length - 1].slice(-1)) {
                results[results.length - 1] =
                    results[results.length - 1].slice(0, -1) +
                        encodeCharacterReference(before.charCodeAt(0));
            }
            if (encodingInfo.after)
                encodeAfter = after;
        }
        tracker.move(value);
        results.push(value);
        before = value.slice(-1);
    }
    indexStack.pop();
    return results.join('');
}
